const calculateTimeLeft = (year) => {
  const to = new Date(year, 0, 1, 0, 0, 0, 0).getTime();
  const from = new Date().getTime();
  let difference = to - from;

  let timeLeft = {};

  if (difference > 0) {
    timeLeft = {
      days: Math.floor(difference / (1000 * 60 * 60 * 24)),
      hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
      minutes: Math.floor((difference / 1000 / 60) % 60),
      seconds: Math.floor((difference / 1000) % 60),
      difference
    };
  }

  return timeLeft;
};

const Timer = ({ year }) => {
  const [timeLeft, setTimeLeft] = useState(calculateTimeLeft(year));

  useEffect(() => {
    const timer = setTimeout(() => {
      setTimeLeft(calculateTimeLeft(year));
    }, 1000);

    return () => clearTimeout(timer);
  });

  return (
    <div>
      {timeLeft.difference > 0 ? (
        <div>
          {timeLeft.days} days {timeLeft.hours} hours {timeLeft.seconds} seconds
        </div>
      ) : (
        <span>Time's up!</span>
      )}
    </div>
  );
